INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cf26e936835120a350',NULL,'analogue','/''ænәlɒg/','n. 类似物, 相似情况\n[医] 类似物, 同型物, 相似器官, 同功异质体；英英释义：n. something having the property of being analogous to something else\na. of a circuit or device having an output that is proportional to the input；词形变化：s:analogues','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('86ca76b5-8d38-46e7-8fbb-05835f876fbe',NULL,'analogy','/ә''nælәdʒi/','n. 相似, 类似\n[计] 模拟；英英释义：n. an inference that if things agree in some respects they probably agree in others\nn. drawing a comparison in order to show a similarity in some respect；词形变化：s:analogies','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1a1f5866e255bbce79',NULL,'analyse','/''ænәlaiz/','vt. 分析, 细察, 分解\n[经] 分析；英英释义：v consider in detail and subject to an analysis in order to discover essential features or meaning\nv break down into components or essential features\nv make a mathematical, chemical, or grammatical analysis of; break down into components or essential features\nv subject to psychoanalytic treatment；词形变化：d:analysed/i:analysing/p:analysed/3:analyses/s:analyses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_24537a112d2b039efd',NULL,'analysis','/ә''nælәsis/','n. 分析\n[计] 分析机; 分析员; 分析; 分析程序；英英释义：n. an investigation of the component parts of a whole and their relations in making up the whole\nn. the abstract separation of a whole into its constituent parts in order to study the parts and their relations\nn. a form of literary criticism in which the structure of a piece of writing is analyzed\nn. the use of closed-class words instead of inflections: e.g., `the father of the bride'' instead of `the bride''s father''；词形变化：s:analyses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_41f88a6cb84cf92cde',NULL,'analytic','/.ænә''litik/','a. 分析的, 善于分析的, 解析的\n[医] 分析的；英英释义：a. using or subjected to a methodology using algebra and calculus\na. using or skilled in using analysis (i.e., separating a whole--intellectual or substantial--into its elemental parts or basic principles)\na. expressing a grammatical category by using two or more words rather than inflection；词形变化：s:analytics','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f80f2520d257e1750f',NULL,'ancestor','/''ænsestә/','n. 祖先, 祖宗；英英释义：n. someone from whom you are descended (but usually more remote than a grandparent)；词形变化：s:ancestors','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_521f4e7ac2ff67b302',NULL,'anchor','/''æŋkә/','n. 锚\nvt. 抛锚停泊, 使固定\n[计] 锚；英英释义：n. a mechanical device that prevents a vessel from moving\nn. a central cohesive source of support and stability\nn. a television reporter who coordinates a broadcast to which several correspondents contribute\nv. fix firmly and stably；词形变化：s:anchors/i:anchoring/3:anchors/p:anchored/d:anchored','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
