INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b73e9f5e7f459d33c1',NULL,'angle','/''æŋgl/','n. 角, 角度, 角落\nvi. 钓鱼, 谋取, 博取, 斜向移动, 转变角度\nvt. 使转动角度, 在...钓鱼, 获取；英英释义：n. the space between two lines or planes that intersect; the inclination of one line to another; measured in degrees or radians\nn. a member of a Germanic people who conquered England and merged with the Saxons and Jutes to become Anglo-Saxons\nv. move or proceed at an angle\nv. fish with a hook；词形变化：s:angles/d:angled/i:angling/p:angled/3:angles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f91a93d92c31ebc4e3',NULL,'anguish','/''æŋgwiʃ/','n. 剧痛, 痛苦\nvt. 使极痛苦\nvi. 感到痛苦；英英释义：n. extreme mental distress\nn. extreme distress of body or mind\nv. suffer great pains or distress；词形变化：i:anguishing/s:anguishes/p:anguished/3:anguishes/d:anguished','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f50fcca513de1552af',NULL,'ankle','/''æŋkl/','n. 踝\n[医] 踝, 踝关节；英英释义：n. a gliding joint between the distal ends of the tibia and fibula and the proximal end of the talus；词形变化：s:ankles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3de8437ded29f735bc',NULL,'anniversary','/æni''vә:sәri/','n. 周年纪念；英英释义：n. the date on which an event occurred in some previous year (or the celebration of it)；词形变化：s:anniversaries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2126c071c43b63f7fd',NULL,'announce','/ә''nauns/','vt. 宣布, 声称, 显示, 预告\nvi. 当报幕员, 宣布参加竞选；英英释义：v. make known; make an announcement\nv. announce publicly or officially\nv. give the names of\nv. foreshadow or presage；词形变化：p:announced/d:announced/i:announcing/3:announces','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_aad65d62135bd51b79',NULL,'annual','/''ænjuәl/','n. 年刊, 年报\na. 每年的, 一年一次的, 全年的, 一年生的；英英释义：n. (botany) a plant that completes its entire life cycle within the space of a year\nn. a reference book that is published regularly once every year\na. completing its life cycle within a year\ns. occurring or payable every year；词形变化：s:annuals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_395ca2e1b49bc58af7',NULL,'anonymous','/ә''nɒnimәs/','a. 姓氏不详的, 无名的, 无特色的\n[计] 无记录；英英释义：a. having no known name or identity or known source\ns. not known or lacking marked individuality','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_18578d72048fab0860',NULL,'ant','/ænt/','n. 蚂蚁；英英释义：n. social insect living in organized colonies; characteristically the males and fertile queen have wings during breeding season; wingless sterile females are the workers；词形变化：s:ants/p:anted/i:anting','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e05a9de9d5aebb5795',NULL,'antenna','/æn''tenә/','n. 天线, 触须, 触角\n[化] 天线；英英释义：n. an electrical device that sends or receives radio or television signals\nn. sensitivity similar to that of a receptor organ\nn. one of a pair of mobile appendages on the head of e.g. insects and crustaceans; typically sensitive to touch and taste；词形变化：s:antennas','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('cb6a189d-3a54-44e9-b001-e50ab205bdc9',NULL,'anticipate','/æn''tisipeit/','vt. 预期, 占先, 加速, 提前使用\n[医] 提前出现, 先期发生；英英释义：v. act in advance of; deal with ahead of time\nv. realize beforehand\nv. be excited or anxious about\nv. be a forerunner of or occur earlier than；词形变化：d:anticipated/i:anticipating/p:anticipated/3:anticipates','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_393995efeda2fb1d47',NULL,'antique','/æn''ti:k/','n. 古董, 古物\na. 古老的, 古风的, 旧式的, 过时的；英英释义：n. any piece of furniture or decorative object or the like produced in a former period and valuable because of its beauty or rarity\nv. shop for antiques\nv. give an antique appearance to\ns. made in or typical of earlier times and valued for its age；词形变化：s:antiques/p:antiqued/i:antiquing/3:antiques/d:antiqued','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fa0f0322c0274764de',NULL,'anxiety','/æŋ''zaiәti/','n. 焦虑, 忧虑, 令人焦虑的事\n[医] 焦虑；英英释义：n. (psychiatry) a relatively permanent state of worry and nervousness occurring in a variety of mental disorders, usually accompanied by compulsive behavior or attacks of panic\nn. a vague unpleasant emotion that is experienced in anticipation of some (usually ill-defined) misfortune；词形变化：s:anxieties','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
