INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_874df60ca98c25d263',NULL,'application','/.æpli''keiʃәn/','n. 应用, 申请, 志愿书, 应用程序\n[计] 应用, 应用程序；英英释义：n. the act of bringing something to bear; using it for a particular purpose\nn. a verbal or written request for assistance or employment or admission to a school\nn. the work of applying something; \nn. a program that gives a computer instructions that provide the user with tools to accomplish a task；词形变化：s:applications','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
