INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c62cb38c3f0e1ca8bc',NULL,'appointment','/ә''pɒintmәnt/','n. 约会, 委任的职位, 委派\n[经] 任命, 派, 指定；英英释义：n. the act of putting a person into a non-elective position\nn. (usually plural) furnishings and equipment (especially for a ship or hotel)\nn. the job to which you are (or hope to be) appointed\nn. (law) the act of disposing of property by virtue of the power of appointment；词形变化：s:appointments','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
