INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5f310b78cf2d58db1e',NULL,'appropriate','/ә''prәupriәt/','a. 适当的\n[经] 适当的, 拨出, 占用；英英释义：v. take possession of by force, as after an invasion\na. suitable for a particular person or place or condition etc；词形变化：d:appropriated/3:appropriates/p:appropriated/i:appropriating','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
