INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2cef88a88be1603206',NULL,'approve','/ә''pru:v/','vt. 赞同, 核准, 为...提供证据\nvi. 赞许；英英释义：v. give sanction to\nv. judge to be right or commendable; think well of；词形变化：d:approved/p:approved/i:approving/3:approves','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_67848084ceda2ed696',NULL,'approximate','/ә''prɒksimәt/','a. 大约的, 接近的, 近似的\nvt. 接近, 使接近, 粗略估计\nvi. 接近于；英英释义：v. be close or similar\ns. not quite exact or correct\ns. very close in resemblance\ns. located close together；词形变化：i:approximating/3:approximates/d:approximated/p:approximated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2820929f70d2947740',NULL,'apt','/æpt/','a. 有...倾向的, 易于的, 恰当的, 聪明的\n[计] 自动数控语言, 自动图象传输, 自动程序控制, 自动程序设计工具；英英释义：s. (usually followed by `to'') naturally disposed toward\ns. at risk of or subject to experiencing something usually unpleasant\ns. mentally quick and resourceful；词形变化：s:apts/r:apter/t:aptest','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('cb13ab10-515d-492e-8489-095b5853a2db',NULL,'arbitrary','/''ɑ:bitrәri/','a. 任意的, 武断的, 专治的, 霸道的；英英释义：a. based on or subject to individual discretion or preference or sometimes impulse or caprice','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_73499585a4770f97d6',NULL,'arch','/ɑ:tʃ/','n. 拱门, 拱形, 足弓\nvt. 使成弓形\nvi. 拱起, 成弓形\na. 主要的, 调皮的, 傲慢无礼的, 狡猾的；英英释义：n. a curved shape in the vertical plane that spans an opening\nn. a curved bony structure supporting or enclosing organs (especially the inner sides of the feet)\nn. a passageway under a curved masonry construction\nn. (architecture) a masonry construction (usually curved) for spanning an opening and supporting the weight above it；词形变化：s:arches/p:arched/i:arching/d:arched/3:arches','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_899f1fada7ac5e3f4a',NULL,'architect','/''ɑ:kitekt/','n. 建筑师, 设计者, 缔造者；英英释义：n. someone who creates plans to be used in making something (such as buildings)；词形变化：s:architects','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_84f07135dd511615e8',NULL,'architecture','/''ɑ:kitektʃә/','n. 建筑学, 建筑式样\n[计] 体系结构；英英释义：n. an architectural product or work\nn. the discipline dealing with the principles of design and construction and ornamentation of fine buildings\nn. the profession of designing buildings and environments with consideration for their esthetic effect；词形变化：s:architectures','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1797164af94ccfaf7e',NULL,'archive','/''ɑ:kaiv/','vt. 把...存档\nn. 档案馆, 档案文件\n[计] 挡案库, 存档；英英释义：n. a depository containing historical records and documents\nv. put into an archive；词形变化：s:archives/i:archiving/d:archived/p:archived/3:archives','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a5726cc9540e285146',NULL,'area','/''єәriә/','n. 区域, 面积, 范围, 空地\n[计] 区域；英英释义：n. a particular geographical region of indefinite boundary (usually serving some special purpose or distinguished by its people or culture or geography)\nn. a subject of study\nn. a part of an animal that has a special function or is supplied by a given artery or nerve\nn. a part of a structure having some specific characteristic or function；词形变化：s:areas','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7f552ea5a1c69c5093',NULL,'argue','/''ɑ:gju/','vi. 提出理由, 争论, 辩论\nvt. 主张, 辩论, 证明, 说服；英英释义：v. present reasons and arguments\nv. have an argument about something\nv. give evidence of；词形变化：d:argued/p:argued/3:argues/i:arguing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_101a03c9e3d5d60870',NULL,'argument','/''ɑ:gjumәnt/','n. 争论, 论证, 论据, 自变量\n[计] 参数；英英释义：n. a fact or assertion offered as evidence that something is true\nn. a discussion in which reasons are advanced for and against some proposition or proposal\nn. a summary of the subject or plot of a literary work or play or movie\nn. (computer science) a reference or value that is passed to a function, procedure, subroutine, command, or program；词形变化：s:arguments','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2d2c6a0246a3d943cc',NULL,'arise','/ә''raiz/','vi. 站立, 出现, 起来；英英释义：v. originate or come into being\nv. rise to one''s feet\nv. result or issue；词形变化：i:arising/3:arises/p:arose/d:arisen','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_301a0a861c7469bc7f',NULL,'arithmetic','/ә''riθmәtik/','n. 算术, 算术知识\n[机] 算术; 算术的；英英释义：n. the branch of pure mathematics dealing with the theory of numerical calculations；词形变化：s:arithmetics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b7498030629e83e009',NULL,'army','/''ɑ:mi/','n. 军队, 陆军；英英释义：n. a permanent organization of the military land forces of a nation or state\nn. a large number of people united for some specific purpose；词形变化：s:armies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8cced8c91d56cd809f',NULL,'arouse','/ә''rauz/','vt. 唤醒, 鼓励, 引起\nvi. 醒来；英英释义：v. call forth (emotions, feelings, and responses)\nv. to begin moving, "As the thunder started the sleeping children began to stir"\nv. stimulate sexually；词形变化：d:aroused/p:aroused/i:arousing/3:arouses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f08051d8a369c011ed',NULL,'arrange','/ә''reindʒ/','v. 安排, 排列, 达成协议\n[计] 重排；英英释义：v. put into a proper or systematic order\nv. make arrangements for\nv. adapt for performance in a different way\nv. arrange thoughts, ideas, temporal events；词形变化：d:arranged/i:arranging/p:arranged/3:arranges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_be7d00739c9fe2a551',NULL,'array','/ә''rei/','n. 排列, 衣服, 大批, 军队\nvt. 布署, 打扮, 排列\n[计] 数组; 阵列；英英释义：n. an orderly arrangement\nn. an impressive display\nn. especially fine or decorative clothing\nn. an arrangement of aerials spaced to give desired directional characteristics；词形变化：s:arrays/p:arrayed/d:arrayed/i:arraying/3:arrays','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_43d4fdd5f5ff45ef68',NULL,'arrest','/ә''rest/','n. 逮捕, 监禁\nvt. 拘捕, 抑制, 吸引, 阻止；英英释义：n. the state of inactivity following an interruption；词形变化：d:arrested/s:arrests/i:arresting/p:arrested/3:arrests','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0ac08c5cb8b0d6c08f',NULL,'arrival','/ә''raivl/','n. 到达, 抵达, 到达者\n[经] 到达, 到达物；英英释义：n. accomplishment of an objective\nn. the act of arriving at a certain place\nn. someone who arrives (or has arrived)；词形变化：s:arrivals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6e0e3d207d7b26caac',NULL,'arrogant','/''ærәɡәnt/','a. 自大的, 傲慢的；英英释义：s. having or showing feelings of unwarranted importance out of overbearing pride','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d97094d9e90f4006b2',NULL,'arrow','/''ærәu/','n. 箭, 箭状物, 箭头记号；英英释义：n. a mark to indicate a direction or relation\nn. a projectile with a straight thin shaft and an arrowhead on one end and stabilizing vanes on the other; intended to be shot from a bow；词形变化：s:arrows/p:arrowed/i:arrowing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_18440eae62d745e0de',NULL,'art','/ɑ:t/','n. 艺术, 人文科学, 技术, 巧妙, 诡计, 美术\n[计] 实际保持时间, 特许权和资源表, 平均检索时间, 平均运行时间；英英释义：n. the products of human creativity; works of art collectively\nn. the creation of beautiful or significant things\nn. a superior skill that you can learn by study and practice and observation；词形变化：s:arts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d3c06f21163c66b9c0',NULL,'artery','/''ɑ:tәri/','n. 动脉, 干道, 要道\n[医] 动脉；英英释义：n. a blood vessel that carries blood from the heart to the body\nn. a major thoroughfare that bears important traffic；词形变化：s:arteries','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
