INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d8f1b87818e482855d',NULL,'articulate','/ɑ:''tikjulit/','a. 发音清晰的, 口才好的\nvt. 明白地说, 以关节连接, 使成为系统的整体；英英释义：v. unite by forming a joint or joints\nv. express or state clearly\na. expressing yourself easily or characterized by clear expressive language；词形变化：d:articulated/i:articulating/3:articulates/p:articulated','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4e68187d148902805d',NULL,'artificial','/.ɑ:ti''fiʃәl/','a. 人造的, 假的, 非原地产的\n[医] 人工的, 人造的, 伟牟；英英释义：a. contrived by art rather than nature\ns. artificially formal\ns. not arising from natural growth or characterized by vital processes；词形变化：s:artificials','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_737d22ab756691341b',NULL,'artist','/''ɑ:tist/','n. 艺术家, 画家；英英释义：n. a person whose creative work shows sensitivity and imagination；词形变化：s:artists','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a79351ca4f91141b1a',NULL,'artistic','/ɑ:''tistik/','a. 艺术的, 艺术家的, 富有艺术性的；英英释义：a. relating to or characteristic of art or artists\ns. satisfying aesthetic standards and sensibilities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
