INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_29716bf65e77812590',NULL,'boil','/bɒil/','n. 煮沸, 沸腾, 疖\nv. 煮沸, 激动；英英释义：n. a painful sore with a hard core filled with pus\nv. come to the boiling point and change from a liquid to vapor\nv. immerse or be immersed in a boiling liquid, often for cooking purposes\nv. bring to, or maintain at, the boiling point；词形变化：i:boiling/d:boiled/3:boils/p:boiled/s:boils','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5e151cb10083fbd434',NULL,'bold','/bәuld/','a. 大胆的\nn. 粗体\n[计] 粗体；英英释义：a. fearless and daring\ns. clear and distinct；词形变化：r:bolder/t:boldest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
