INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7251046e998334781c',NULL,'champion','/''tʃæmpiәn/','n. 冠军, 拥护者, 战士\nvt. 保卫, 拥护\na. 优胜的；英英释义：n. someone who has won first place in a competition\nn. someone who fights for a cause\nv. protect or fight for as a champion\ns. holding first place in a contest；词形变化：s:champions/d:championed/i:championing/p:championed/3:champions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1ff493a35a0cb95757',NULL,'chance','/tʃæns. tʃɑ:ns/','n. 机会, 意外, 可能性\nvi. 偶然发生\nvt. 冒险；英英释义：n. a risk involving danger\nv. be the case by chance；词形变化：s:chances/p:chanced/d:chanced/i:chancing/3:chances','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_52ef1ba3482b182b30',NULL,'chancellor','/''tʃɑ:nsәlә/','n. 大臣, 总理, 首相, 大使馆/领事馆的一等秘书, 司法官, 大学校长；英英释义：n. the person who is head of state (in several countries)\nn. the honorary or titular head of a university；词形变化：s:chancellors','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7599b9ff3438869001',NULL,'channel','/''tʃænәl/','n. 海峡, 航道, 频道\nvt. 引导, 在...上挖沟, 形成河道\n[计] 信道, 通道；英英释义：n. a path over which electrical signals can pass\nn. a passage for water (or other fluids) to flow through\nn. a deep and relatively narrow body of water (as in a river or a harbor or a strait linking two larger bodies) that allows the best passage for vessels\nn. (often plural) a means of communication or access；词形变化：s:channels/d:channelled/i:channelling/p:channelled/3:channels','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bb4b2fecf59533c5bc',NULL,'chaos','/''keiɒs/','n. 大混乱, 混沌\n[化] 混沌; 浑沌；英英释义：n. a state of extreme confusion and disorder\nn. the formless and disordered state of matter before the creation of the cosmos\nn. (Greek mythology) the most ancient of gods; the personification of the infinity of space preceding creation of the universe\nn. (physics) a dynamical system that is extremely sensitive to its initial conditions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cceaa81db241b44316',NULL,'chap','/tʃæp/','n. 小伙子, 颌, 龟裂\nv. 皲裂；英英释义：n. a boy or man\nn. a crack in a lip caused usually by cold\nn. (usually in the plural) leather leggings without a seat; joined by a belt; often have flared outer flaps; worn over trousers by cowboys to protect their legs\nv. crack due to dehydration；词形变化：s:chaps/i:chapping/p:chapped/3:chaps/d:chapped','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_70d83377d4562b9534',NULL,'chapter','/''tʃæptә/','n. 章, 篇, 重要章节\n[计] 章; 段；英英释义：n. a subdivision of a written work; usually numbered and titled\nn. any distinct period in history or in a person''s life\nn. a local branch of some fraternity or association\nn. an ecclesiastical assembly of the monks in a monastery or even of the canons of a church；词形变化：s:chapters','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_661a7762c1555e5eba',NULL,'character','/''kærәktә/','n. 个性, 字符, 人物, 性质, 品格, 资格\n[计] 字符；英英释义：n. the inherent complex of attributes that determines a persons moral and ethical actions and reactions\nn. an actor''s portrayal of someone in a play\nn. a person of a specified kind (usually with many eccentricities)\nn. good repute；词形变化：s:characters/i:charactering/p:charactered/3:characters/d:charactered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2ad0a67d0bc840f0da',NULL,'characteristic','/.kærәktә''ristik/','n. 特性, 特征, 特色\na. 特性的, 特有的, 有特色的\n[计] 阶; 指数；英英释义：n. a distinguishing quality\nn. the integer part (positive or negative) of the representation of a logarithm; in the expression log 643 = 2.808 the characteristic is 2\nn. any measurable property of a device measured under closely specified conditions\na. typical or distinctive；词形变化：s:characteristics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
