INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_95064705bc9db320cd',NULL,'choose','/tʃu:z/','vt. 选择, 宁愿, 欲\nvi. 作出选择, 愿意\n[计] 选取；英英释义：v. pick out, select, or choose from a number of alternatives\nv. select as an alternative over another\nv. see fit or proper to act in a certain way; decide to act in a certain way；词形变化：d:chosen/p:chose/i:choosing/3:chooses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
