INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5a3448a6dc5fed11b9',NULL,'circular','/''sә:kjulә/','a. 圆形的, 循环的, 间接的\n[医] 环状的, 循环的；英英释义：n. an advertisement (usually printed on a page or in a leaflet) intended for wide distribution\ns. describing a circle; moving in a circle；词形变化：s:circulars','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b78ba0eddf353f15eb',NULL,'circulate','/''sә:kjuleit/','v. (使)流通, (使)循环, (使)传播；英英释义：v. cause to become widely known\nv. cause be distributed\nv. move through a space, circuit or system, returning to the starting point\nv. cause to move in a circuit or system；词形变化：d:circulated/i:circulating/p:circulated/3:circulates','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3575169481e5778bb6',NULL,'circumference','/sә''kʌmfәrәns/','n. 圆周, 周缘, 胸围\n[医] 周缘, 环状面；英英释义：n. the size of something as given by the distance around it\nn. the boundary line encompassing an area or object\nn. the length of the closed curve of a circle；词形变化：s:circumferences','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6b9ab11c6305f487f3',NULL,'circus','/''sә:kәs/','n. 马戏团, 马戏, 竞技场；英英释义：n. a travelling company of entertainers; including trained animals\nn. a performance given by a traveling company of acrobats, clowns, and trained animals\nn. a frenetic disorganized (and often comic) disturbance suggestive of a large public entertainment\nn. (antiquity) an open-air stadium for chariot races and gladiatorial games；词形变化：s:circuses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
