INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_033d573a8302a6cac1',NULL,'colony','/''kɒlәni/','n. 殖民地, 移民队\n[医] 菌(集)落, 菌丛; 移民区；英英释义：n. a body of people who settle far from home but maintain ties with their homeland; inhabitants remain nationals of their home state but are not literally under the home state''s system of government\nn. a group of organisms of the same type living or growing together\nn. one of the 13 British colonies that formed the original states of the United States\nn. a place where a group of people with the same interest or occupation are concentrated；词形变化：s:colonies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
