INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fed24423121cde5432',NULL,'combat','/''kɒmbæt/','n. 争斗, 战斗\nvi. 战斗, 争斗\nvt. 与...战斗, 与...斗争；英英释义：n. an engagement fought between two military forces；词形变化：i:combating/3:combats/d:combatted/p:combated','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
