INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0f43d52e43d039f1e4',NULL,'compact','/kәm''pækt/','a. 紧凑的, 紧密的, 简洁的\nvt. 使紧密结合, 压缩\nvi. 变坚实；英英释义：n. a small cosmetics case with a mirror; to be carried in a woman''s purse\nn. a small and economical car\nv. have the property of being packable or of compacting easily\na. closely and firmly united or packed together；词形变化：s:compacts/d:compacted/3:compacts/i:compacting/r:compacter/p:compacted','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d8b555ec9cc83495ba',NULL,'companion','/kәm''pænjәn/','n. 朋友, 陪伴, 指南, 升降口围罩\nvt. 陪伴；英英释义：n. a friend who is frequently in the company of another\nn. a traveler who accompanies you\nn. one paid to accompany or assist or live with another；词形变化：s:companions/i:companioning/p:companioned/3:companions/d:companioned','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_36e69cb952225b716b',NULL,'comparable','/''kɒmpәrәbl/','a. 可比较的, 比得上的；英英释义：a. able to be compared or worthy of comparison\ns. conforming in every respect','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2ffc3858bb397781bd',NULL,'comparative','/kәm''pærәtiv/','a. 比较的, 相对的\nn. 对手；英英释义：n. the comparative form of an adjective or adverb\na. relating to or based on or involving comparison；词形变化：s:comparatives','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6d29c4f7dae6c2d591',NULL,'compare','/kәm''pєә/','vt. 比较, 比喻, 对照\nvi. 相比\nn. 比较\n[计] 比较；英英释义：v. examine and note the similarities or differences of\nv. be comparable\nv. consider or describe as similar, equal, or analogous\nv. to form the comparative or superlative form on an adjective or adverb；词形变化：d:compared/i:comparing/3:compares/p:compared','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
