INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_eb093c48ab1408994e',NULL,'compartment','/kәm''pɑ:tmәnt/','n. 分隔间, 卧车包房, 防水舱隔\n[医] 隔室, 隔间；英英释义：n. a space into which an area is subdivided\nn. a partitioned section, chamber, or separate room within a larger enclosed area；词形变化：s:compartments/d:compartmented/p:compartmented','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
