INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_163e2dca6b735da545',NULL,'compassion','/kәm''pæʃәn/','n. 同情, 怜悯；英英释义：n. a deep awareness of and sympathy for another''s suffering\nn. the humane quality of understanding the suffering of others and wanting to do something about it；词形变化：s:compassions','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('a8562cff-237e-4726-b954-3887ec442f36',NULL,'compatible','/kәm''pætәbl/','a. 能共处的, 可并立的, 适合的\n[计] 相容的; 兼容的；英英释义：a. able to exist and perform in harmonious or agreeable combination\na. capable of being used with or connected to other devices or components without modification\ns. capable of forming a homogeneous mixture that neither separates nor is altered by chemical interaction；词形变化：s:compatibles/3:compatibles','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('837e0924-8e01-4f9f-85dd-c22aaa8802a1',NULL,'compel','/kәm''pel/','vt. 强迫, 迫使；英英释义：v. force somebody to do something\nv. necessitate or exact；词形变化：d:compelled/i:compelling/p:compelled/3:compels/s:compels','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
