INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_96cee3d1bcd923e6b6',NULL,'compensate','/''kɒmpenseit/','v. 偿还, 补偿, 付报酬；英英释义：v. adjust for\nv. make amends for; pay compensation for\nv. make payment to; compensate；词形变化：d:compensated/i:compensating/3:compensates/p:compensated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_21f969b2020fddabd4',NULL,'compensation','/.kɒmpen''seiʃәn/','n. 补偿, 赔偿金, 工资\n[医] 代偿(机能), 补偿；英英释义：n. something (such as money) given or received as payment or reparation (as for a service or loss or injury)\nn. (psychiatry) a defense mechanism that conceals your undesirable shortcomings by exaggerating desirable behaviors；词形变化：s:compensations','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
