INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c0ad60dff9521a089b',NULL,'competent','/''kɒmpitәnt/','a. 能干的, 胜任的, 有效的, 足够的\n[经] 有权的, 授权的, 胜任的；英英释义：a. properly or sufficiently qualified or capable or efficient\ns. adequate for the purpose\na. legally qualified or sufficient','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ddbfdc7287292fc13c',NULL,'competition','/.kɒmpi''tiʃәn/','n. 竞争, 竞赛\n[经] 竞争, 竞销, 比赛；英英释义：n. a business relation in which two parties compete to gain customers\nn. the act of competing as for profit or a prize；词形变化：s:competitions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_05af248f5d6adfc093',NULL,'competitive','/kәm''petitiv/','a. 竞争的\n[经] 竞争的；英英释义：a. involving competition or competitiveness\ns. subscribing to capitalistic competition\ns. showing a fighting disposition','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('077ee133-0c95-441f-a7bd-c0148f1c0709',NULL,'compile','/kәm''pail/','vt. 编译, 编辑, 编纂, 收集\n[计] 编译；英英释义：v. use a computer program to translate source code written in a particular programming language into computer-readable machine code that can be executed；词形变化：d:compiled/i:compiling/p:compiled/3:compiles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_82a26525ca8086872b',NULL,'complain','/kәm''plein/','v. 抱怨, 抗议, 控诉；英英释义：v. express complaints, discontent, displeasure, or unhappiness\nv. make a formal accusation; bring a formal charge；词形变化：p:complained/i:complaining/d:complained/3:complains','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7c3da421c8cf7ca62c',NULL,'complaint','/kәm''pleint/','n. 诉苦, 抱怨, 控诉\n[医] 陈诉; 病；英英释义：n. (formerly) a loud cry (or repeated cries) of pain or rage or sorrow\nn. an expression of grievance or resentment\nn. (civil law) the first pleading of the plaintiff setting out the facts on which the claim for relief is based；词形变化：s:complaints','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
