INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ba34cdc9046c468cca',NULL,'complete','/kәm''pli:t/','a. 完全的, 十足的, 完成的\nvt. 完成, 完工, 使圆满；英英释义：v. come or bring to a finish or an end; others finished in over 4 hours"\nv. bring to a whole, with all the necessary parts or elements\nv. complete a pass\nv. write all the required information onto a form；词形变化：d:completed/p:completed/i:completing/3:completes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5674ec06992f26ec61',NULL,'complex','/kәm''pleks/','n. 综合体, 情结, 络合物\na. 复杂的, 组合的；英英释义：n. a conceptual whole made up of complicated and related parts\nn. a compound described in terms of the central atom to which other atoms are bound or coordinated\nn. (psychoanalysis) a combination of emotions and impulses that have been rejected from awareness but still influence a person''s behavior\na. complicated in structure; consisting of interconnected parts；词形变化：s:complexes/p:complexed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8c3ae297d2fd3813a0',NULL,'compliance','/kәm''plaiәns/','n. 遵从, 顺从, 屈从\n[化] 柔顺; 顺应；英英释义：n acting according to certain accepted standards\nn a disposition or tendency to yield to the will of others\nn the act of submitting; usually surrendering power to another；词形变化：s:compliances','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_80f88befe19eafec00',NULL,'complicate','/''kɒmplikeit/','vt. 弄复杂, 使错综, 使恶化\nvi. 变复杂；英英释义：v. make more complicated\nv. make more complex, intricate, or richer；词形变化：d:complicated/3:complicates/p:complicated/i:complicating','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a64741082a8c399fc4',NULL,'complicated','/''kɒmplikeitid/','a. 复杂的\n[医] 并发的；英英释义：s. difficult to analyze or understand；词形变化：d:complicated/0:complicated/1:dp/p:complicated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c69f0c33d5801dfd7f',NULL,'complication','/.kɒmpli''keiʃәn/','n. 复杂化, 复杂情况\n[医] 并发症, 并发病；英英释义：n. the act or process of complicating\nn. a situation or condition that is complex or confused\nn. any disease or disorder that occurs during the course of (or because of) another disease\nn. a development that complicates a situation；词形变化：s:complications','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c799825442b3ac4707',NULL,'compliment','/''kɒmplimәnt/','n. 称赞, 恭维, 敬意\nvt. 称赞, 褒扬, 恭维；英英释义：n. a remark (or act) expressing praise and admiration\nv. say something to someone that expresses praise\nv. express respect or esteem for；词形变化：s:compliments/p:complimented/d:complimented/i:complimenting/3:compliments','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e6c878c08efa759486',NULL,'comply','/kәm''plai/','vi. 顺从, 依从\n[法] 遵守, 承诺, 照做；英英释义：v. act in accordance with someone''s rules, commands, or wishes；词形变化：d:complied/i:complying/p:complied/3:complies','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2d7982184b72848bea',NULL,'component','/kәm''pәunәnt/','n. 元件, 组件, 成分\na. 组成的, 构成的\n[计] 组件；英英释义：n. an abstract part of something\nn. an artifact that is one of the individual parts of which a composite entity is made up; especially a part that can be separated from or attached to a system；词形变化：s:components','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_09dfea0b841a7914ca',NULL,'compose','/kәm''pәuz/','vt. 组成, 写作, 作曲, 使平静\nvi. 创作, 排字\n[计] 编写；英英释义：v. form the substance of\nv. write music\nv. put together out of existing material\nv. calm (someone, especially oneself); make quiet；词形变化：d:composed/p:composed/i:composing/3:composes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_18a15de4ea97bf6492',NULL,'composite','/kәm''pɒzit/','a. 合成的, 混合成的, 菊科的\nn. 合成物, 复合材料, 菊科；英英释义：n. considered the most highly evolved dicotyledonous plants, characterized by florets arranged in dense heads that resemble single flowers\ns. consisting of separate interconnected parts\na. of or relating to or belonging to the plant family Compositae；词形变化：s:composites','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_30ef1b3d21a0565529',NULL,'composition','/kɒmpә''ziʃәn/','n. 作文, 创作, 组成\n[化] 成分; 组成；英英释义：n. the spatial property resulting from the arrangement of parts in relation to each other and to the whole\nn. a mixture of ingredients\nn. an essay (especially one written as an assignment)\nn. something that is created by arranging several things to form a unified whole；词形变化：s:compositions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1d9c01056e0576c30d',NULL,'compound','/kәm''paund/','n. 混合物, 复合词, 化合物, 院子\na. 复合的, 混合的, 化合的\nvi. 化合, 和解, 妥协\nvt. 使复合, 使化合；英英释义：n. a whole formed by a union of two or more elements or parts\nn. (chemistry) a substance formed by chemical union of two or more elements or ingredients in definite proportion by weight\nn. an enclosure of residences and other building (especially in the Orient)\nv. put or add together；词形变化：s:compounds/d:compounded/3:compounds/i:compounding/p:compounded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f989aaf5e2d15293a6',NULL,'comprehend','/.kɒmpri''hend/','vt. 理解, 包括；英英释义：v get the meaning of something\nv to become aware of through the senses\nv include in scope; include as part of something broader; have as one''s sphere or territory；词形变化：d:comprehended/i:comprehending/p:comprehended/3:comprehends','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_edec405d724436b55d',NULL,'comprehension','/.kɒmpri''henʃәn/','n. 理解, 包含；英英释义：n. an ability to understand the meaning or importance of something (or the knowledge acquired as a result)','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('d39d003a-f800-4324-a973-195a7c834d13',NULL,'comprehensive','/.kɒmpri''hensiv/','a. 广泛的, 有理解力的, 综合的\n[经] 广泛的, 综合的, 全面的；英英释义：a. including all or everything\ns. broad in scope；词形变化：s:comprehensives','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dbbb01ee1bc3e40a05',NULL,'compress','/kәm''pres/','vt. 压缩, 压紧\nvi. 受压缩小\n[计] 压缩程序；英英释义：n. a cloth pad or dressing (with or without medication) applied firmly to some part of the body (to relieve discomfort or reduce fever)\nv. make more compact by or as if by pressing\nv. squeeze or press together；词形变化：d:compressed/i:compressing/p:compressed/3:compresses/s:compresses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
